110→// floating-point to Q(destination type)
111→static inline q15_t convert_float_to_q15(float x)
112→{
113→    q31_t q31;
114→    q15_t q15;
115→    x *= 32768.0f;
116→    x += (x < 0.0f ? -0.5f : 0.5f);
117→    q31 = (q31_t)x;
118→    if (q31 >= 32768)
119→    {
120→        q15 = INT16_MAX;
121→    }
122→    else if (q31 <= -32768)
123→    {
124→        q15 = INT16_MIN;
125→    }
126→    else
127→    {
128→        q15 = (q15_t)q31;
129→    }
130→    return q15;
131→}
