357→/**
358→ * nds_saturate(q31_t src, uin32_t (destination_type))
359→ *      Comput the saturation value to the input data.
360→ */
361→
362→/**
363→ * @brief saturate to dst_type.
364→ * @param[in]   src input value.
365→ * @param[in]   type destination type.
366→ * @return saturate value of the destination type.
367→ */
368→
369→//only support 16u and 8u types.
370→//32u does need to saturate since the incoming type is q31_t.
371→#ifdef __NDS32_EXT_PERF__
372→
373→//This function can not be decalred as inline function in -O0.
374→//The 2nd argument will be treated as variable instead of immediate value since it will not be inlined in -O0.
375→//So this function should be only as a MACRO for all compiler configuration.
376→#define nds_saturate(X, Y) (q31_t)__nds32__clips(X, Y - 1)
377→
378→#else
379→
380→static inline q31_t nds_saturate(q31_t src, const uint32_t type)
381→{
382→    q31_t max, min;
383→
384→    if (type == 16u)
385→    {
386→        max = INT16_MAX;
387→        min = INT16_MIN;
388→    }
389→    else
390→    {
391→        max = INT8_MAX;
392→        min = INT8_MIN;
393→    }
394→
395→    return (src > max) ? max : (src < min) ? min : src;
396→}
397→
398→#endif // __NDS32_EXT_PERF__
