 26→
 27→int32_t riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any(const int8_t * in_tensor,
 28→                                                          const uint16_t in_tensor_dim_x,
 29→                                                          const uint16_t in_tensor_dim_y,
 30→                                                          const uint16_t in_tensor_ch,
 31→                                                          const uint16_t in_tensor_batch,
 32→                                                          const int8_t * ker_weight,
 33→                                                          const uint16_t out_tensor_ch,
 34→                                                          const uint16_t pad_x,
 35→                                                          const uint16_t pad_y,
 36→                                                          const uint16_t stride_x,
 37→                                                          const uint16_t stride_y,
 38→                                                          const int32_t * bias,
 39→                                                          int8_t * out_tensor,
 40→                                                          const int32_t * out_shift,
 41→                                                          const int32_t * out_scale,
 42→                                                          const int32_t out_offset,   //value is in the range of [-128, 127]
 43→                                                          const int32_t in_offset,    //value is in the range of [-127, 128]
 44→                                                          const int32_t act_min,
 45→                                                          const int32_t act_max,
 46→                                                          const uint16_t out_tensor_dim_x,
 47→                                                          const uint16_t out_tensor_dim_y,
 48→                                                          int16_t * tmp_buf)
 49→{
 50→#ifdef ENA_EMPTY_FUN
 51→    //empty body
 52→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING)
 53→    if ((pad_x != 0) ||
 54→        (pad_y != 0))
 55→    {
 56→        return -1;
 57→    }
 58→
 59→    /////////////////////////////////////////////////// START CALC CONTRI///////////////////////////////////////
 60→    // calculate the weight contribution
 61→    int32_t contri_buf[out_tensor_ch];
 62→    const int8_t *pWt = ker_weight;
 63→    long vl;
 64→    long maxvl_per_vg;
 65→    NDS_VEC_VSETVLI(maxvl_per_vg, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 66→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 67→    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
 68→
 69→    if (bias != NULL)
 70→    {
 71→        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
 72→        {
 73→            long in_tensor_ch2 = in_tensor_ch;
 74→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 75→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
 76→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 77→            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot
 78→
 79→            while (in_tensor_ch2 >= maxvl_per_vg)
 80→            {
 81→                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 82→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
 83→                pWt += vl;
 84→                in_tensor_ch2 -= vl;
 85→
 86→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 87→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 88→            }
 89→
 90→            //clean one of the dot product source
 91→            long tmp_vl = in_tensor_ch2 + 3;
 92→            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 93→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
 94→            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 95→            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);
 96→
 97→            while (in_tensor_ch2 > 0)
 98→            {
 99→                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
100→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
101→                pWt += vl;
102→                in_tensor_ch2 -= vl;
103→
104→                vl = (vl + 3) >> 2;
105→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
106→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
107→            }
108→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
109→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
110→
111→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
112→            const int32_t *pBias = &bias[cur_out_ch];
113→            NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);
114→            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution back
115→            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);    // add bias
116→
117→            int32_t *pContri_buf = &contri_buf[cur_out_ch];
118→            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
119→        }
120→    }
121→    else
122→    {
123→        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
124→        {
125→            long in_tensor_ch2 = in_tensor_ch;
126→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
127→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
128→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
129→            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);    // const one for vd4dot
130→
131→            while (in_tensor_ch2 >= maxvl_per_vg)
132→            {
133→                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
134→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
135→                pWt += vl;
136→                in_tensor_ch2 -= vl;
137→
138→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
139→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
140→            }
141→
142→            //clean one of the dot product source
143→            long tmp_vl = in_tensor_ch2 + 3;
144→            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
145→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
146→            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
147→            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);
148→
149→            while (in_tensor_ch2 > 0)
150→            {
151→                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
152→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
153→                pWt += vl;
154→                in_tensor_ch2 -= vl;
155→
156→                vl = (vl + 3) >> 2;
157→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
158→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
159→            }
160→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
161→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
162→
163→            // add input_offset contribution back
164→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
165→            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
166→
167→            int32_t *pContri_buf = &contri_buf[cur_out_ch];
168→            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
169→        }
170→    }
171→    /////////////////////////////////////////////////// END CALC CONTRI///////////////////////////////////////
172→
173→    //cache is 512KB, type is q7
174→    uint32_t tiling_size = 256;
175→    const long align_byte = 64;
176→    unsigned long addr_in_tmp_buf;
177→    int8_t *pOut = out_tensor;
178→    int8_t *src1 = (int8_t *) in_tensor;
179→    int8_t *src2;
180→    int32_t *dst_i32;
181→
182→    if ((stride_x == 1) && (stride_y == 1))
183→    {
184→        src2 = (int8_t *)tmp_buf;
185→    }
186→    else
187→    {
188→        src2 = (int8_t *)tmp_buf + sizeof(*in_tensor) * tiling_size * in_tensor_ch; //matrix_A's memory space
189→        src2 = (int8_t *)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
190→    }
191→
192→    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
193→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
194→    dst_i32 = (int32_t *)addr_in_tmp_buf;
195→
196→    //transpose the kernel_weight for matrix multiplication
197→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch);
198→
199→    if ((stride_x == 1) && (stride_y == 1))
200→    {
201→        for(int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
202→        {
203→            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
204→                                                          src2,
205→                                                          dst_i32,
206→                                                          pOut,
207→                                                          out_scale,
208→                                                          out_shift,
209→                                                          in_tensor_dim_x * in_tensor_dim_y,
210→                                                          in_tensor_ch,
211→                                                          out_tensor_ch,
212→                                                          out_offset,
213→                                                          act_min,
214→                                                          act_max,
215→                                                          contri_buf,
216→                                                          tiling_size);
217→            /* next in_tensor batch offset */
218→            src1 += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
219→        }
220→    }
221→    else
222→    {
223→        for(int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
224→        {
225→            int8_t *pBuffer = (int8_t *)tmp_buf;
226→            int col_counter = 0;
227→            int16_t i_out_y, i_out_x;
228→
229→            /* This part implements the im2col function */
230→            for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
231→            {
232→                for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
233→                {
234→                    /* Copying the pixel data to column */
235→                    nn_dup_s8((int8_t *)in_tensor + (i_out_y * stride_y * in_tensor_dim_x + i_out_x * stride_x) * in_tensor_ch, pBuffer, in_tensor_ch);
236→                    pBuffer += in_tensor_ch;
237→                    col_counter++;
238→
239→                    /* Computation is filed for [tiling_size] columns */
240→                    if (col_counter == tiling_size)
241→                    {
242→                        pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
243→                                                                      src2,
244→                                                                      dst_i32,
245→                                                                      pOut,
246→                                                                      out_scale,
247→                                                                      out_shift,
248→                                                                      col_counter,
249→                                                                      in_tensor_ch,
250→                                                                      out_tensor_ch,
251→                                                                      out_offset,
252→                                                                      act_min,
253→                                                                      act_max,
254→                                                                      contri_buf,
255→                                                                      tiling_size);
256→                        /* reset */
257→                        col_counter = 0;
258→                        pBuffer = (int8_t *)tmp_buf;
259→                    }
260→                }
261→            }
262→
263→            /* check if there is left-over for compute */
264→            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
265→                                                          src2,
266→                                                          dst_i32,
267→                                                          pOut,
268→                                                          out_scale,
269→                                                          out_shift,
270→                                                          col_counter,
271→                                                          in_tensor_ch,
272→                                                          out_tensor_ch,
273→                                                          out_offset,
274→                                                          act_min,
275→                                                          act_max,
276→                                                          contri_buf,
277→                                                          tiling_size);
278→            /* next in_tensor batch offset */
279→            in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
280→        }
281→    }
