  27→int32_t riscv_nn_fc_s8_s16_s8_sym_bias_fast(const q7_t * in_vec,
  28→                                        const q7_t * wt_mat,
  29→                                        const uint16_t size,
  30→                                        const uint16_t wt_row_num,
  31→                                        const uint16_t pre_rshift,
  32→                                        const uint16_t out_scale,
  33→                                        const uint16_t post_rshift,
  34→                                        const q31_t * bias,
  35→                                        q15_t * out_vec,
  36→                                        q15_t * in_tmp_buf)
  37→{
  38→#ifdef ENA_EMPTY_FUN
  39→    //empty body
  40→#elif defined(ENA_VEC_ISA)
  41→#if 0   //vwmacc
  42→    const q7_t *pB = wt_mat;
  43→    const q31_t *pBias = bias;
  44→    q15_t *pO = out_vec;
  45→    const q7_t *pA;
