  53→    //(following generating mask codes could be optimized later if SEW>32 is supported)
  54→    NDS_VEC_VSETVLI_E16(vl, colCnt);
  55→    NDS_VEC_VID_V(NDS_VEC_V0);
  56→    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x7);           //index mod 8
  57→    NDS_VEC_VMSLE_VI(NDS_VEC_V1, NDS_VEC_V0, 0x3);          //8n ~ 8n+3
  58→    NDS_VEC_VMSGT_VI(NDS_VEC_V2, NDS_VEC_V0, 0x3);          //8n+4 ~ 8n+7
