 907→        *pO++ = (NDS_DSP_SATS((sum4 >> post_rshift), 16));
 908→
 909→        /* adjust the pointers and counters */
 910→        rowCnt--;
 911→    }
 912→
 913→    /* left-over part of the rows */
 914→    rowCnt = wt_row_num & 0x3;
 915→    while (rowCnt)
 916→    {
 917→        q31_t     sum = *pBias++;
 918→        uint16_t  colCnt = size >> 2;
 919→
 920→        pA = in_tmp_buf;
 921→
 922→        while (colCnt)
 923→        {
 924→            q31_t     inV1, inV2, inM11, inM12;
 925→
 926→            pB = (q7_t *) read_and_pad_reordered((void *)pB, &inM11, &inM12);
 927→            inV1 = *__SIMD32(pA)++;
 928→            sum = NDS_DSP_KMADA(sum, inV1, inM11);
 929→            inV2 = *__SIMD32(pA)++;
 930→            sum = NDS_DSP_KMADA(sum, inV2, inM12);
 931→            colCnt--;
 932→        }
 933→
 934→        /* left-over of the vector */
 935→        colCnt = size & 0x3;
 936→        while (colCnt)
 937→        {
 938→            q15_t     inV = *pA++;
 939→            q7_t      inM = *pB++;
 940→            sum += inV * inM;
 941→            colCnt--;
 942→        }
 943→
 944→        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 945→        *pO++ = (NDS_DSP_SATS((sum >> post_rshift), 16));
 946→
 947→        rowCnt--;
 948→    }
 949→#else // general
 950→    uint16_t  rowCnt = wt_row_num >> 2;
 951→    const q7_t *pB = wt_mat;
 952→    const q7_t *pA;
 953→    q15_t     *pO = out_vec;
 954→    const q31_t *pBias = bias;
 955→
 956→    while (rowCnt)
 957→    {
 958→        q31_t     sum =  *pBias++;
 959→        q31_t     sum2 = *pBias++;
 960→        q31_t     sum3 = *pBias++;
 961→        q31_t     sum4 = *pBias++;
 962→
 963→        uint16_t  colCnt = size >> 2;
 964→
 965→        pA = in_vec;
 966→
 967→        while (colCnt)
 968→        {
 969→            q7_t      inA1 = *pA++;
 970→            q7_t      inA3 = *pA++;
 971→            q7_t      inA2 = *pA++;
 972→            q7_t      inA4 = *pA++;
 973→
 974→            q7_t      inB1 = *pB++;
 975→            q7_t      inB3 = *pB++;
 976→            q7_t      inB2 = *pB++;
 977→            q7_t      inB4 = *pB++;
 978→
 979→            sum += inA1 * inB1 + inA2 * inB2;
 980→            sum2 += inA1 * inB3 + inA2 * inB4;
 981→
 982→            inB1 = *pB++;
 983→            inB3 = *pB++;
 984→            inB2 = *pB++;
 985→            inB4 = *pB++;
 986→
 987→            sum3 += inA1 * inB1 + inA2 * inB2;
 988→            sum4 += inA1 * inB3 + inA2 * inB4;
 989→
 990→            inB1 = *pB++;
 991→            inB3 = *pB++;
 992→            inB2 = *pB++;
 993→            inB4 = *pB++;
 994→
 995→            sum += inA3 * inB1 + inA4 * inB2;
 996→            sum2 += inA3 * inB3 + inA4 * inB4;
 997→
 998→            inB1 = *pB++;
 999→            inB3 = *pB++;
1000→            inB2 = *pB++;
1001→            inB4 = *pB++;
1002→
1003→            sum3 += inA3 * inB1 + inA4 * inB2;
1004→            sum4 += inA3 * inB3 + inA4 * inB4;
1005→
1006→            colCnt--;
1007→        }
1008→        colCnt = size & 0x3;
1009→        while (colCnt)
1010→        {
1011→            q7_t      inA = *pA++;
1012→            q7_t      inB = *pB++;
1013→            sum += inA * inB;
1014→            inB = *pB++;
1015→            sum2 += inA * inB;
1016→            inB = *pB++;
1017→            sum3 += inA * inB;
1018→            inB = *pB++;
1019→            sum4 += inA * inB;
1020→
1021→            colCnt--;
1022→        }
1023→        sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1024→        sum2 = (sum2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1025→        sum3 = (sum3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1026→        sum4 = (sum4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1027→#ifdef ENA_DSP_ISA
1028→        *pO++ = NDS_DSP_SATS((sum >> post_rshift), 16);
1029→        *pO++ = NDS_DSP_SATS((sum2 >> post_rshift), 16);
1030→        *pO++ = NDS_DSP_SATS((sum3 >> post_rshift), 16);
1031→        *pO++ = NDS_DSP_SATS((sum4 >> post_rshift), 16);
1032→#else
1033→        *pO++ = NDS_ISA_SATS((sum >> post_rshift), 16);
1034→        *pO++ = NDS_ISA_SATS((sum2 >> post_rshift), 16);
1035→        *pO++ = NDS_ISA_SATS((sum3 >> post_rshift), 16);
1036→        *pO++ = NDS_ISA_SATS((sum4 >> post_rshift), 16);
1037→#endif
1038→
1039→        rowCnt--;
1040→    }
1041→
1042→    rowCnt = wt_row_num & 0x3;
1043→
1044→    while (rowCnt)
1045→    {
1046→        int ip_out = *pBias++;
1047→        int j;
1048→
1049→        pA = in_vec;
1050→        for (j = 0; j < size; j++)
1051→        {
1052→            q7_t      inA = *pA++;
1053→            q7_t      inB = *pB++;
1054→            ip_out += inA * inB;
1055→        }
1056→        ip_out = (ip_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1057→#ifdef ENA_DSP_ISA
1058→        *pO++ = NDS_DSP_SATS((ip_out >> post_rshift), 16);
1059→#else
1060→        *pO++ = NDS_ISA_SATS((ip_out >> post_rshift), 16);
1061→#endif
1062→
1063→        rowCnt--;
1064→    }
1065→#endif
1066→    return 0;
1067→}
